def {{nama_fungsi}}(filepath):
    """Read image dimensions and format from file header.
    Support: PNG, JPEG, GIF, BMP, WebP.
    Returns dict: {'width': int, 'height': int, 'format': str} or None if unknown.
    """
    with open(filepath, 'rb') as f:
        header = f.read(32)
    if len(header) < 8:
        return None
    # PNG
    if header[:8] == b'\x89PNG\r\n\x1a\n':
        w = struct.unpack('>I', header[16:20])[0]
        h = struct.unpack('>I', header[20:24])[0]
        return {'width': w, 'height': h, 'format': 'PNG'}
    # GIF
    if header[:6] in (b'GIF87a', b'GIF89a'):
        w = struct.unpack('<H', header[6:8])[0]
        h = struct.unpack('<H', header[8:10])[0]
        return {'width': w, 'height': h, 'format': 'GIF'}
    # BMP
    if header[:2] == b'BM':
        w = struct.unpack('<i', header[18:22])[0]
        h = abs(struct.unpack('<i', header[22:26])[0])
        return {'width': abs(w), 'height': h, 'format': 'BMP'}
    # WebP
    if header[:4] == b'RIFF' and header[8:12] == b'WEBP':
        if header[12:16] == b'VP8 ':
            w = struct.unpack('<H', header[26:28])[0] & 0x3FFF
            h = struct.unpack('<H', header[28:30])[0] & 0x3FFF
        elif header[12:16] == b'VP8L':
            bits = struct.unpack('<I', header[21:25])[0]
            w = (bits & 0x3FFF) + 1
            h = ((bits >> 14) & 0x3FFF) + 1
        else:
            w = h = 0
        return {'width': w, 'height': h, 'format': 'WebP'}
    # JPEG
    if header[:2] == b'\xff\xd8':
        return _parse_jpeg(filepath)
    return None


def _parse_jpeg(filepath):
    """Parse JPEG dimensions by scanning SOF markers."""
    with open(filepath, 'rb') as f:
        f.read(2)  # skip SOI
        while True:
            marker = f.read(2)
            if len(marker) < 2:
                break
            if marker[0] != 0xFF:
                break
            mtype = marker[1]
            if mtype in (0xC0, 0xC1, 0xC2):  # SOF markers
                f.read(3)  # length + precision
                h = struct.unpack('>H', f.read(2))[0]
                w = struct.unpack('>H', f.read(2))[0]
                return {'width': w, 'height': h, 'format': 'JPEG'}
            else:
                length = struct.unpack('>H', f.read(2))[0]
                f.read(length - 2)
    return None
